const https = require('https');
const { JSDOM } = require('jsdom');

async function fetchUrlMetadata(url) {
    return new Promise((resolve, reject) => {
        https.get(url, (res) => {
            let data = '';

            res.on('data', (chunk) => {
                data += chunk;
            });

            res.on('end', () => {
                const dom = new JSDOM(data);
                const document = dom.window.document;

                const metadata = {
                    title: document.querySelector('title') ? document.querySelector('title').textContent : '',
                    description: document.querySelector('meta[name="description"]') ? document.querySelector('meta[name="description"]').content : '',
                    ogTags: {}
                };

                const ogTags = document.querySelectorAll('meta[property^="og:"]');
                ogTags.forEach(tag => {
                    const property = tag.getAttribute('property');
                    const content = tag.getAttribute('content');
                    if (property && content) {
                        metadata.ogTags[property] = content;
                    }
                });

                resolve(metadata);
            });

            res.on('error', (err) => {
                reject(err);
            });
        }).on('error', (err) => {
            reject(err);
        });
    });
}

module.exports = { fetchUrlMetadata };